   if (match(&I, m_c_And(m_Value(Y), m_OneUse(m_CombineOr(
@@ -4099,6 +4143,10 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
     return BinaryOperator::CreateXor(Or, ConstantInt::get(Ty, *CV));
   }

